  "summary": "<p>This is a sample landing page designed to be a starting point for your website</p>",
  "copy": "<div class="signup-container">
  <h2>Create Account</h2>
  <form id="signupForm"><label for="name">Full Name</label><input type="text" id="name" name="name" required="" /><label for="email">Email</label><input type="email" id="email" name="email" required="" /><label for="phone">Phone</label><input type="text" id="phone" name="phone" /><label for="hawaiianName">Hawaiian Name</label><input type="text" id="hawaiianName" name="hawaiianName" /><label for="password">Password</label><input type="password" id="password" name="password" required="" /><button type="submit">Sign Up</button></form>
  <p>Already have an account? /sign-inLogin</p>
</div>
<div class="row sectionBlockLayout text-start" style="display: flex; flex-wrap: wrap; margin: 0px; min-height: auto; padding: 8px;">
  <div class="container" style="padding: 0px; display: flex; flex-wrap: wrap;"><div class="col-lg-12 columnBlockLayout" style="flex-grow: 1; display: flex; flex-direction: column; min-width: 250px;"></div></div>
</div>
